// Sort a list in JavaScript

// 1. Using the sort() method with a comparison function:
const numbers = [3, 1, 4, 1, 5, 9, 2, 6];
numbers.sort(function(a, b) {
  return a - b; // Ascending order
});
console.log(numbers); // Output: [1, 1, 2, 3, 4, 5, 6, 9]

// 2. Using the sort() method with a concise arrow function:
const fruits = ["banana", "apple", "orange"];
fruits.sort((a, b) => {
  return a.localeCompare(b); // Ascending order (lexicographical)
});
console.log(fruits); // Output: [ 'apple', 'banana', 'orange'

