// Closure in JavaScript
// A closure is the combination of a function and the lexical environment within which that function was declared.
// It allows an inner function to access variables from its outer function's scope, even after the outer function has finished executing.
function outerFunction() {
  let outerVar = "Hello";

  function innerFunction() {
    console.log(outerVar); // Accessing outerVar from the outer function's scope
  }

  return innerFunction;
}

let myClosure = outerFunction();
myClosure(); // Output: Hello
```

